const body = $input.first().json.body;
const fields = body?.data?.fields || [];

let fullName = '';
let email = '';
let fileUrl = '';

for (const field of fields) {
  const label = (field.label || '').toLowerCase();
  const value = field.value;

  if (label.includes('name')) {
    fullName = value || '';
  }
  if (label.includes('email')) {
    email = value || '';
  }
  if (label.includes('pdf') || label.includes('file') || label.includes('document') || label.includes('upload')) {
    if (Array.isArray(value) && value.length > 0) {
      fileUrl = value[0].url || '';
    }
  }
}

if (!email) throw new Error('Email nahi mili form se');
if (!fileUrl) throw new Error('PDF URL nahi mila form se');

return [{
  json: {
    fullName: fullName || 'User',
    email,
    fileUrl
  }
}];

const pdfData = $input.first().json;
const prev = $('Extract Form Data').first().json;

const resumeText = pdfData.text || pdfData.content || '';

if (!resumeText.trim()) {
  throw new Error('PDF se text nahi mila - searchable PDF use karo');
}

// Groq ke liye request body banao
const requestBody = {
  model: 'llama-3.3-70b-versatile',
  temperature: 0.3,
  max_tokens: 1500,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'You are an expert document analyst. Reply with valid JSON only. No markdown. No extra text.'
    },
    {
      role: 'user',
      content: `Analyze this document and return JSON only:\n\nDOCUMENT:\n${resumeText.slice(0, 4000)}\n\nReturn exactly this JSON structure:\n{\n"title": "document title or topic in 5-7 words",\n"summary": "clear 3-4 sentence summary of the entire document",\n"key_points": ["point 1", "point 2", "point 3", "point 4", "point 5"],\n"action_items": ["action 1", "action 2", "action 3"],\n"document_type": "type of document (report/article/contract/manual etc)",\n"word_count_estimate": 500\n}`
    }
  ]
};

return [{
  json: {
    groq_body: JSON.stringify(requestBody),
    email: prev.email,
    fullName: prev.fullName,
    fileUrl: prev.fileUrl
  }
}];

const groqResponse = $input.first().json;
const prev = $('Build Groq Request').first().json;

let analysis;
try {
  const rawText = groqResponse.choices[0].message.content;
  analysis = JSON.parse(rawText);
} catch(e) {
  throw new Error('Groq JSON parse error: ' + e.message);
}

// Key points HTML banao
const keyPointsHtml = (analysis.key_points || []).map(p => 
  `<li style="margin-bottom: 8px;">${p}</li>`
).join('');

// Action items HTML banao
const actionItemsHtml = (analysis.action_items || []).map(a => 
  `<li style="margin-bottom: 8px;">✅ ${a}</li>`
).join('');

// Email HTML banao
const emailHtml = `
<div style="font-family: Arial, sans-serif; max-width: 600px; color: #1a1a1a; line-height: 1.8;">

  <div style="background: #1a1a2e; color: white; padding: 24px; border-radius: 8px 8px 0 0;">
    <h2 style="margin: 0; font-size: 20px;">📄 Document Summary Ready</h2>
    <p style="margin: 6px 0 0 0; opacity: 0.8; font-size: 13px;">Powered by Groq AI</p>
  </div>

  <div style="padding: 24px; background: #f9f9f9; border: 1px solid #eee;">

    <p>Dear ${prev.fullName},</p>
    <p>Your document has been analyzed. Here is the complete summary:</p>

    <div style="background: white; border-left: 4px solid #4f46e5; padding: 16px 20px; margin: 20px 0; border-radius: 4px;">
      <p style="margin: 0 0 4px 0; font-size: 12px; color: #888;">DOCUMENT TITLE</p>
      <p style="margin: 0; font-weight: bold; font-size: 16px;">${analysis.title || 'Untitled Document'}</p>
      <p style="margin: 8px 0 0 0; font-size: 12px; color: #888;">Type: ${analysis.document_type || 'Document'}</p>
    </div>

    <h3 style="color: #1a1a2e; border-bottom: 2px solid #4f46e5; padding-bottom: 8px;">📋 Summary</h3>
    <p style="background: white; padding: 16px; border-radius: 8px; border: 1px solid #eee;">${analysis.summary}</p>

    <h3 style="color: #1a1a2e; border-bottom: 2px solid #4f46e5; padding-bottom: 8px;">🔑 Key Points</h3>
    <ul style="background: white; padding: 16px 16px 16px 36px; border-radius: 8px; border: 1px solid #eee; margin: 0;">
      ${keyPointsHtml}
    </ul>

    <h3 style="color: #1a1a2e; border-bottom: 2px solid #4f46e5; padding-bottom: 8px;">🎯 Action Items</h3>
    <ul style="background: white; padding: 16px 16px 16px 36px; border-radius: 8px; border: 1px solid #eee; margin: 0; list-style: none;">
      ${actionItemsHtml}
    </ul>

    <p style="margin-top: 32px; font-size: 12px; color: #999;">This summary was auto-generated by your n8n PDF Summarizer workflow.</p>

  </div>
</div>`;

return [{
  json: {
    email: prev.email,
    fullName: prev.fullName,
    email_html: emailHtml,
    title: analysis.title || 'Document Summary',
    subject: `📄 Summary Ready: ${analysis.title || 'Your Document'}`
  }
}];
